// Validate this is a push to main and extract changed/removed files.
// GitHub delivers commits[].added, commits[].modified, commits[].removed.
const payload = $input.first().json.body || $input.first().json;

const ref = payload.ref || '';
if (ref !== 'refs/heads/main') {
  console.log(`Skipping push to non-main ref: ${ref}`);
  return [];
}

const beforeSha = payload.before;
const afterSha = payload.after;
const repoFullName = payload.repository?.full_name || 'j0sh3rs/home-ops';

const changedFiles = new Set();
const removedFiles = new Set();

for (const commit of (payload.commits || [])) {
  for (const f of (commit.added || [])) changedFiles.add(f);
  for (const f of (commit.modified || [])) changedFiles.add(f);
  for (const f of (commit.removed || [])) {
    removedFiles.add(f);
    changedFiles.delete(f);
  }
}

const isMdDoc = f =>
  f === 'CLAUDE.md' ||
  f.startsWith('docs/runbooks/') && f.endsWith('.md') ||
  f.startsWith('docs/research/') && f.endsWith('.md') ||
  f.startsWith('docs/') && f.endsWith('.md');

const isYamlManifest = f =>
  (f.startsWith('kubernetes/') || f.startsWith('talos/')) &&
  (f.endsWith('kustomization.yaml') || f.endsWith('helmrelease.yaml'));

const items = [];

for (const file of changedFiles) {
  if (isMdDoc(file)) {
    items.push({ json: { fileType: 'md', file, repoFullName, afterSha, action: 'upsert' } });
  } else if (isYamlManifest(file)) {
    items.push({ json: { fileType: 'yaml', file, repoFullName, afterSha, action: 'upsert' } });
  }
}

for (const file of removedFiles) {
  if (isMdDoc(file) || isYamlManifest(file)) {
    items.push({ json: { fileType: 'deleted', file, repoFullName, afterSha, action: 'delete' } });
  }
}

console.log(`Push to main: ${items.filter(i=>i.json.action==='upsert').length} to upsert, ${items.filter(i=>i.json.action==='delete').length} to delete`);
return items;

// Merge file metadata (from the parse node, two items back) with raw content.
// In n8n, after an HTTP Request node the previous item context is carried in $input.
// We re-attach metadata from the upstream item via pairedItem.
const raw = $input.item.json;
const meta = $input.item.pairedItem;

// The HTTP Request with text response puts the body in `data` when responseFormat=text.
// Fall back gracefully.
const rawContent = typeof raw === 'string' ? raw : (raw.data || raw.body || JSON.stringify(raw));

// Re-attach routing metadata from the paired upstream item.
const fileType = $('Parse Push Payload').item.json.fileType;
const file = $('Parse Push Payload').item.json.file;

return [{ json: { rawContent, fileType, file } }];

// For Markdown docs: pass content through with title derived from file path.
// Strips leading # from first heading if present.
const { rawContent, file } = $json;

const firstLine = rawContent.split('\n')[0]?.trim() || '';
const titleFromHeading = firstLine.startsWith('#') ? firstLine.replace(/^#+\s*/, '') : '';
const titleFromPath = file.replace(/^.*\//, '').replace(/\.md$/, '');
const title = titleFromHeading || titleFromPath;

return [{ json: { textContent: rawContent, title, file } }];

// For YAML manifests: extract comments + kind/name/namespace metadata.
// Comments (lines starting with #) often contain intent and context.
const { rawContent, file } = $json;

const lines = rawContent.split('\n');
const comments = lines
  .filter(l => l.trim().startsWith('#'))
  .map(l => l.trim().replace(/^#+\s?/, ''));

// Extract key metadata fields via simple regex scan (not a full YAML parse).
const extract = (pattern) => {
  const m = rawContent.match(pattern);
  return m ? m[1].trim() : null;
};

const kind = extract(/^kind:\s*(.+)/m);
const name = extract(/^  name:\s*(.+)/m) || extract(/^name:\s*(.+)/m);
const namespace = extract(/^  namespace:\s*(.+)/m) || extract(/^namespace:\s*(.+)/m);
const chart = extract(/(?:chart|url):\s*oci:\/\/([^\s]+)/m);
const imageRepo = extract(/repository:\s*([^\s]+)/m);
const imageTag = extract(/tag:\s*([^\s]+)/m);

const title = [kind, name].filter(Boolean).join(' / ') || file.replace(/^.*\//, '').replace(/\.yaml$/, '');

const sections = [
  `# ${title}`,
  ``,
  `**File:** \`${file}\``,
  kind ? `**Kind:** ${kind}` : null,
  name ? `**Name:** ${name}` : null,
  namespace ? `**Namespace:** ${namespace}` : null,
  chart ? `**Chart:** ${chart}` : null,
  (imageRepo && imageTag) ? `**Image:** ${imageRepo}:${imageTag}` : null,
  ``,
];

if (comments.length > 0) {
  sections.push(`## Comments / Intent`);
  sections.push(``),
  sections.push(...comments.map(c => `- ${c}`));
  sections.push(``);
}

const textContent = sections.filter(l => l !== null).join('\n');

return [{ json: { textContent, title, file } }];

// Build the document title the same way as upsert so the DELETE matches.
const { file } = $json;
const titleFromPath = file.replace(/^.*\//, '').replace(/\.(md|yaml)$/, '');
return [{ json: { deleteTitle: titleFromPath, file } }];

const results = $input.all();
console.log(`Sync complete. Processed ${results.length} item(s).`);
return [{ json: { status: 'ok', processed: results.length, completedAt: new Date().toISOString() } }];
